class JobMain extends Main{static skillOperate(id){}static jobInit(){let jobs=arrayShuffle(Skills.jobNames);for(let i=0;i<this.playNum;i++)Object.assign(this.pars[i],{job:jobs[i%jobs.length],skill:"",skillRound:0}),$(`#${this.pars[i].name} > div > #job`).textContent=this.pars[i].job}static compute(){}static async game(){await sleep(2e3);let player=new JobPlayer(0);return this.init(),$("#log1").textContent="初始化完成, 正在分配职业",await sleep(1e3),this.jobInit(),$("#log1").textContent="职业分配完成，即将开始游戏",await sleep(1500),Swal.fire("Error","Uncaught ReferenceError: skillOperate is not defined","error")}}class JobPlayer extends Player{}class Skills{static jobNames=["时停者","脑裂者","追光者","逆转者","重生者","报应者","君醒者"];static"时停者"(id,target){let param=Main.pars[id];return!(JobMain.round-param.skillRound<=2)&&(param.skillRound=JobMain.round,param.skill="时停",param.operation="",param.target=target,!0)}}